func application(_ app: UIApplication, open url: URL, options: [UIApplicationOpenURLOptionsKey : Any] = [:]) -> Bool {
    // Parse the URL components
    let components = URLComponents(url: url, resolvingAgainstBaseURL: true)
    
    // Navigate to the appropriate view controller
    switch components?.path {
        case "/profile/\(userId)":
            let profileVC = ProfileViewController()
            profileVC.userId = userId
            navigationController?.pushViewController(profileVC, animated: true)
        case "/payment/confirm":
            let paymentConfirmVC = PaymentConfirmationViewController()
            navigationController?.pushViewController(paymentConfirmVC, animated: true)
        case "/admin/settings":
            let adminSettingsVC = AdminSettingsViewController()
            navigationController?.pushViewController(adminSettingsVC, animated: true)
        default:
            // Handle other URLs as needed
    }
}